import React from 'react';
import { Link, useLocation } from 'react-router-dom';
import { useAuth } from '../../context/AuthContext';

export default function Navbar() {
  const { user, logout, role } = useAuth();
  const { pathname } = useLocation();

  const links = role === 'ADMIN'
    ? [{ to: '/admin',   label: 'Dashboard' }]
    : role === 'COURIER'
    ? [{ to: '/courier', label: 'Panel' }, { to: '/orders', label: 'Buyurtmalar' }]
    : [
        { to: '/',              label: 'Bosh sahifa' },
        { to: '/orders/new',    label: 'Buyurtma' },
        { to: '/orders',        label: 'Tarix' },
      ];

  return (
    <nav style={s.nav}>
      <Link to="/" style={s.brand}>
        Xorazm<span style={s.accent}>Delivery</span>
      </Link>

      <div style={s.links}>
        {links.map(({ to, label }) => (
          <Link key={to} to={to} style={{
            ...s.link,
            ...(pathname === to ? s.linkActive : {})
          }}>
            {label}
          </Link>
        ))}
      </div>

      <div style={s.right}>
        {user ? (
          <>
            <span style={s.phone}>{user.phone}</span>
            <button style={s.logoutBtn} onClick={logout}>Chiqish</button>
          </>
        ) : (
          <Link to="/login" style={s.loginBtn}>Kirish</Link>
        )}
      </div>
    </nav>
  );
}

const s = {
  nav:      { background:'#fff', borderBottom:'1px solid rgba(13,122,106,0.12)',
              display:'flex', alignItems:'center', padding:'0 24px', height:58, gap:16 },
  brand:    { fontFamily:'Syne,sans-serif', fontWeight:800, fontSize:18, color:'#0D7A6A',
              textDecoration:'none', flexShrink:0 },
  accent:   { color:'#EF9F27' },
  links:    { display:'flex', gap:4, flex:1 },
  link:     { padding:'6px 12px', borderRadius:8, fontSize:14, fontWeight:500,
              color:'#6b8080', textDecoration:'none' },
  linkActive:{ background:'#0D7A6A', color:'#fff' },
  right:    { display:'flex', alignItems:'center', gap:10 },
  phone:    { fontSize:13, color:'#6b8080' },
  logoutBtn:{ padding:'6px 14px', background:'transparent', border:'1px solid rgba(13,122,106,0.2)',
              borderRadius:8, fontSize:13, cursor:'pointer', color:'#6b8080' },
  loginBtn: { padding:'7px 16px', background:'#0D7A6A', color:'#fff', borderRadius:8,
              fontSize:13, fontWeight:600, textDecoration:'none' },
};
